#nullable enable // autogenerated  

using PVZEngine;
using PVZEngine.Base;

namespace MVZ2.Metas
{
    /// <summary>  
    /// 间接属性引用：先从当前实体定义读取一个 NamespaceID 属性（如 starting_armor），  
    /// 再用该 ID 作为 target 去查找另一个定义类型（如 armor）的属性（如 maxHealth）。  
    /// </summary>  
    public class AlmanacVariableReferenceIndirectProperty : AlmanacVariableReference
    {
        /// <summary>  
        /// 第一步：从当前实体定义中读取的属性名（返回值应为 NamespaceID）。  
        /// 例如 "mvz2:entity/starting_armor"  
        /// </summary>  
        public string indirectPropertyName;

        /// <summary>  
        /// 第二步：用第一步得到的 NamespaceID 作为 definitionID，在此类型中查找定义。  
        /// 例如 "armor"  
        /// </summary>  
        public string resolveType;

        /// <summary>  
        /// 第三步：从解析到的定义中读取的最终属性名。  
        /// 例如 "mvz2:armor/maxHealth"  
        /// </summary>  
        public string propertyName;

        public AlmanacVariableReferenceIndirectProperty(string indirectPropertyName, string resolveType, string propertyName)
        {
            this.indirectPropertyName = indirectPropertyName;
            this.resolveType = resolveType;
            this.propertyName = propertyName;
        }

        public override object? GetVariableValue(AlmanacVariableContext context)
        {
            var main = context.main;
            var definitionType = context.currentDefinitionType;
            var definitionID = context.currentDefinitionID;

            // 第一步：从当前实体定义中读取间接属性（应返回 NamespaceID）  
            var currentDefinition = main.Game.GetDefinition<Definition>(definitionType, definitionID);
            if (currentDefinition == null)
                return null;

            var indirectKey = PropertyMapper.ConvertFromName(indirectPropertyName);
            var indirectValue = currentDefinition.GetPropertyObject(indirectKey);

            // 间接属性的值应该是一个 NamespaceID  
            if (indirectValue is not NamespaceID resolvedID || !NamespaceID.IsValid(resolvedID))
                return null;

            // 第二步：用解析到的 ID 和 resolveType 查找目标定义  
            var targetDefinition = main.Game.GetDefinition<Definition>(resolveType, resolvedID);
            if (targetDefinition == null)
                return null;

            // 第三步：从目标定义中读取最终属性  
            var finalKey = PropertyMapper.ConvertFromName(propertyName);
            return targetDefinition.GetPropertyObject(finalKey);
        }
    }
}